mapper.select:
SELECT id, user_id, name, initial_amount, asset_type, created_at, updated_at, deleted_at
FROM   assets
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL
LIMIT  1

mapper.update:
UPDATE assets
SET    deleted_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL
